function [logTitle,logData,nmbClmn,nmbSht] = fLogReadV05(fName)%% reads logfile and return title and data% % [logTitle,logData,nmbClmn,nmbSht] = fLogReadV04(fName)% % logTitle: cell of the column number and log title% logData: cell of the data (string, not numeric)% nmbClmn: number of column in the log% nmbSht: number of shots in the log%% fName: file path%%% Function Log Reader, ver.5% % Kei Nakamura% 2013/1/3 ver.4: for new control system% 2013/1/17 ver.5: make compatible with matlab log%% load file into a big stringaa = fileread(fName);   % log file in a long string%% find out how many columns and rowsbb = find(aa==10);  % finding "end of the line character"lvL = ~isempty(find(aa==13, 1));  % lab view logic, 1 for lavbiew log, 0 for matlab lognmbSht = numel(bb)-1;   % number of shots is the rows -1 (title row)titleLine = aa(1:bb(1)-1);    % extract title linetitleLLength = numel(titleLine);      % title line lengthtitleLTab = find(titleLine==9);       % title line tab, find tab in title linetitleLTab = [0,titleLTab,titleLLength+1]; % add tabs artificailly at the beginning and end for later conveniencenmbClmn = numel(titleLTab) - 1;   % number of column would be -1.%% make cell array of column number and titlelogTitle = cell(nmbClmn,2);   % title column, allocate empty cell arraystart1 = 1; % for the beginningfor ii = 1:nmbClmn % for the number of column    logTitle{ii,1} = ii;   % column number    logTitle{ii,2} = titleLine(start1:titleLTab(ii+1)-1);    start1 = titleLTab(ii+1)+1;    % for the beginning of the next lineend%% put data in cell arraylogData = cell(nmbSht,nmbClmn); % log data, allocationdataLTab = zeros(1,nmbClmn+1);  % allocationfor ii = 1:nmbSht   % go shot by shot for now    dataLine = aa(bb(ii)+1:bb(ii+1)-1-lvL); % extract each line (shot)    dataLLength = numel(dataLine);      % data line length    dataLTab(2:end-1) = find(dataLine==9); % find tabs for each line    dataLTab(end) = dataLLength+1;  % add tab artificailly at the end    dataElmLength = diff(dataLTab)-1;  % to find data element length    % place data on each column element    strtL = 1;    for jj = 1:nmbClmn        if dataElmLength(jj)>0 % dataElmLength=0 is empty cell            logData{ii,jj} = dataLine(strtL:dataLTab(jj+1)-1);    % put data in cell        end        strtL = dataLTab(jj+1)+1;    endend end
